#include <cstdio>

int main() {
    pid_t pid;
    int fd[2]; // Array to hold file descriptors
    pipe(fd); // Create a pipe

    pid = fork(); // Spawn a new process

    if (pid == -1) {
        std::cerr << "Fork failed" << std::endl;
        return 1;
    } else if (pid == 0) { // Child process
        close(fd[1]); // Close the write end
        dup2(fd[0], STDIN_FILENO); // Redirect stdin to the read end of the pipe
        close(fd[0]); // Close the read end of the pipe
        execlp("cat", "cat", (char *)0); // Execute cat to read from stdin
        perror("execlp");
        _exit(1);
    } else { // Parent process
        close(fd[0]); // Close the read end
        dup2(fd[1], STDOUT_FILENO); // Redirect stdout to the write end of the pipe
        close(fd[1]); // Close the write end
        execlp("cat", "cat", (char *)0); // Execute cat to write to stdout
        perror("execlp");
        _exit(1);
    }

    wait(NULL); // Wait for the child to finish
    return 0;
}
```

